commits.content:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

:root {
    /* Colores personalizados - Inspirados en la marca de Dariluz */
    --primary: #8b5fbf;
    --primary-dark: #6f42c1;
    --secondary: #d6b3ff;
    --accent: #ff6b8a;
    --accent-light: #ff8fa3;
    --text-primary: #ffffff;
    --text-secondary: #e0e0e0;
    --surface: #2a1e3e;
    --background: linear-gradient(135deg, #1a0f2e 0%, #2a1e3e 50%, #1f1a3f 100%);
    --success: #2ecc71;

    /* Typography */
    --font-display: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    --font-body: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;

    /* Spacing */
    --spacing-xs: 0.5rem;
    --spacing-sm: 1rem;
    --spacing-md: 2rem;
    --spacing-lg: 3rem;
    --spacing-xl: 4rem;

    /* Animation */
    --transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

html {
    scroll-behavior: smooth;
}

body {
    font-family: var(--font-body);
    background: var(--background);
    color: var(--text-primary);
    line-height: 1.6;
    overflow-x: hidden;
}

/* =============== NAVIGATION =============== */
.navbar {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    z-index: 1000;
    padding: var(--spacing-md) var(--spacing-lg);
    background: rgba(26, 15, 46, 0.85);
    backdrop-filter: blur(15px);
    border-bottom: 1px solid rgba(139, 95, 191, 0.2);
    animation: slideDown 0.6s ease-out;
}

@keyframes slideDown {
    from {
        opacity: 0;
        transform: translateY(-20px);
    }

    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.nav-container {
    max-width: 1200px;
    margin: 0 auto;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.logo {
    font-size: 1.8rem;
    font-weight: 700;
    background: linear-gradient(135deg, var(--secondary) 0%, var(--accent-light) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    text-decoration: none;
    cursor: pointer;
}

.nav-links {
    display: flex;
    list-style: none;
    gap: var(--spacing-lg);
}

.nav-links a {
    color: var(--text-secondary);
    text-decoration: none;
    transition: var(--transition);
    position: relative;
    font-size: 0.95rem;
    font-weight: 500;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.nav-links a::after {
    content: '';
    position: absolute;
    bottom: -5px;
    left: 0;
    width: 0;
    height: 2px;
    background: linear-gradient(90deg, var(--secondary), var(--accent));
    transition: width 0.3s ease;
}

.nav-links a:hover {
    color: var(--secondary);
}

.nav-links a:hover::after {
    width: 100%;
}

/* =============== HERO SECTION =============== */
.hero {
    min-height: 100vh;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    overflow: hidden;
    padding: var(--spacing-lg);
    padding-top: 80px;
}

.hero::before {
    content: '';
    position: absolute;
    top: -50%;
    right: -20%;
    width: 600px;
    height: 600px;
    background: radial-gradient(circle, var(--secondary) 0%, transparent 70%);
    opacity: 0.12;
    border-radius: 50%;
    animation: float 6s ease-in-out infinite;
}

.hero::after {
    content: '';
    position: absolute;
    bottom: -30%;
    left: -10%;
    width: 500px;
    height: 500px;
    background: radial-gradient(circle, var(--primary) 0%, transparent 70%);
    opacity: 0.08;
    border-radius: 50%;
    animation: float 8s ease-in-out infinite reverse;
}

@keyframes float {

    0%,
    100% {
        transform: translateY(0px);
    }

    50% {
        transform: translateY(30px);
    }
}

.hero-content {
    position: relative;
    z-index: 10;
    max-width: 900px;
    text-align: center;
    animation: slideInUp 0.8s ease-out 0.2s both;
}

@keyframes slideInUp {
    from {
        opacity: 0;
        transform: translateY(40px);
    }

    to {
        opacity: 1;
        transform: translateY(0);
    }
}

h1 {
    font-size: clamp(2.5rem, 8vw, 4.5rem);
    font-weight: 700;
    line-height: 1.2;
    margin-bottom: var(--spacing-md);
    background: linear-gradient(135deg, var(--secondary) 0%, var(--accent-light) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.subtitle {
    font-size: clamp(1rem, 3vw, 1.5rem);
    color: var(--text-secondary);
    margin-bottom: var(--spacing-lg);
    max-width: 600px;
    margin-left: auto;
    margin-right: auto;
}

.cta-buttons {
    display: flex;
    gap: var(--spacing-md);
    justify-content: center;
    flex-wrap: wrap;
    margin-bottom: var(--spacing-lg);
}

.btn {
    padding: 1rem 2.5rem;
    border-radius: 50px;
    border: none;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    transition: var(--transition);
    position: relative;
    overflow: hidden;
    text-decoration: none;
    display: inline-block;
    text-transform: uppercase;
    letter-spacing: 1px;
}

.btn-primary {
    background: linear-gradient(135deg, var(--secondary) 0%, var(--accent-light) 100%);
    color: #000;
    box-shadow: 0 10px 30px rgba(214, 179, 255, 0.3);
}

.btn-primary:hover {
    transform: translateY(-3px);
    box-shadow: 0 15px 40px rgba(214, 179, 255, 0.5);
}

.btn-secondary {
    background: transparent;
    color: var(--secondary);
    border: 2px solid var(--secondary);
}

.btn-secondary:hover {
    background: var(--secondary);
    color: #000;
    transform: translateY(-3px);
}

/* =============== ABOUT SECTION =============== */
.about {
    padding: var(--spacing-xl) var(--spacing-lg);
    margin: 0 auto;
    background: rgba(42, 30, 62, 0.5);
    backdrop-filter: blur(10px);
    border-radius: 20px;
    margin: auto var(--spacing-xl);
    border: 1px solid rgba(139, 95, 191, 0.2);
}

.section-title {
    font-size: clamp(2rem, 5vw, 3rem);
    font-weight: 700;
    margin-bottom: var(--spacing-lg);
    text-align: center;
    color: var(--text-primary);
    background: linear-gradient(135deg, var(--secondary) 0%, var(--accent-light) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.about-content {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: var(--spacing-xl);
    align-items: center;
}

.about-text p {
    margin-bottom: var(--spacing-md);
    color: var(--text-secondary);
    line-height: 1.8;
    font-size: 1.05rem;
}

.skills-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    gap: var(--spacing-md);
    margin-top: var(--spacing-lg);
}

.skill-card {
    background: linear-gradient(135deg, var(--surface) 0%, rgba(214, 179, 255, 0.1) 100%);
    padding: var(--spacing-xs);
    border-radius: 12px;
    text-align: center;
    border: 1px solid rgba(139, 95, 191, 0.3);
    transition: var(--transition);
    cursor: pointer;
}

.skill-card:hover {
    transform: translateY(-5px);
    border-color: var(--secondary);
    background: linear-gradient(135deg, var(--surface) 0%, rgba(214, 179, 255, 0.2) 100%);
    box-shadow: 0 10px 30px rgba(139, 95, 191, 0.2);
}

.skill-card strong {
    color: var(--secondary);
    display: block;
    margin-bottom: var(--spacing-xs);
    font-size: 1.1rem;
}

.skill-card p {
    color: var(--text-secondary);
    font-size: 0.9rem;
}

.about-image {
    position: relative;
    height: 400px;
    background: linear-gradient(135deg, var(--surface) 0%, var(--primary) 100%);
    border-radius: 15px;
    overflow: hidden;
    box-shadow: 0 20px 60px rgba(139, 95, 191, 0.3);
}

.about-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    opacity: 0;
    transition: opacity 0.6s ease;
}

.about-image img.loaded {
    opacity: 1;
}

/* =============== EXPERIENCE SECTION =============== */
.experience {
    padding: var(--spacing-xl) var(--spacing-lg);
    max-width: 1200px;
    margin: 0 auto;
}

.timeline {
    position: relative;
    padding: var(--spacing-lg) 0;
}

.timeline::before {
    content: '';
    position: absolute;
    left: 50%;
    transform: translateX(-50%);
    width: 2px;
    height: 100%;
    background: linear-gradient(180deg, var(--secondary) 0%, transparent 100%);
}

.timeline-item {
    margin-bottom: var(--spacing-xl);
    position: relative;
}

.timeline-item:nth-child(odd) {
    padding-right: calc(50% + var(--spacing-lg));
    text-align: right;
}

.timeline-item:nth-child(even) {
    padding-left: calc(50% + var(--spacing-lg));
}

.timeline-dot {
    position: absolute;
    left: 50%;
    transform: translateX(-50%);
    width: 20px;
    height: 20px;
    background: var(--secondary);
    border: 4px solid var(--background);
    border-radius: 50%;
    top: 0;
    box-shadow: 0 0 0 4px var(--primary);
}

.timeline-content {
    background: linear-gradient(135deg, var(--surface) 0%, rgba(214, 179, 255, 0.1) 100%);
    padding: var(--spacing-md);
    border-radius: 10px;
    border: 1px solid rgba(139, 95, 191, 0.3);
}

.timeline-content h3 {
    color: var(--secondary);
    margin-bottom: var(--spacing-xs);
}

.timeline-content p {
    color: var(--text-secondary);
    margin: 0;
}

/* =============== PORTFOLIO SECTION =============== */
.portfolio {
    padding: var(--spacing-xl) var(--spacing-lg);
    background: linear-gradient(135deg, rgba(214, 179, 255, 0.03) 0%, rgba(139, 95, 191, 0.03) 100%);
}

.portfolio-container {
    max-width: 1200px;
    margin: 0 auto;
}

.portfolio-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
    gap: var(--spacing-lg);
    margin-top: var(--spacing-xl);
}

.portfolio-card {
    position: relative;
    border-radius: 15px;
    overflow: hidden;
    aspect-ratio: 1;
    cursor: pointer;
}

.portfolio-card-image {
    width: 100%;
    height: 100%;
    background: linear-gradient(135deg, var(--surface) 0%, var(--primary) 100%);
    position: relative;
    overflow: hidden;
}

.portfolio-card img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    opacity: 0;
    transition: opacity 0.6s ease;
}

.portfolio-card img.loaded {
    opacity: 1;
}

.portfolio-card-overlay {
    position: absolute;
    inset: 0;
    background: linear-gradient(135deg, rgba(139, 95, 191, 0.9) 0%, rgba(42, 30, 62, 0.9) 100%);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: var(--spacing-md);
    opacity: 0;
    transition: opacity 0.3s ease;
    padding: var(--spacing-lg);
    text-align: center;
}

.portfolio-card:hover .portfolio-card-overlay {
    opacity: 1;
}

.portfolio-card-title {
    font-size: 1.5rem;
    font-weight: 700;
}

.portfolio-card-description {
    font-size: 0.95rem;
    color: rgba(255, 255, 255, 0.9);
}

/* =============== SERVICES SECTION =============== */
.services {
    padding: var(--spacing-xl) var(--spacing-lg);
    max-width: 1200px;
    margin: 0 auto;
}

.services-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: var(--spacing-lg);
    margin-top: var(--spacing-xl);
}

.service-card {
    background: linear-gradient(135deg, var(--surface) 0%, rgba(214, 179, 255, 0.1) 100%);
    padding: var(--spacing-lg);
    border-radius: 15px;
    border: 1px solid rgba(139, 95, 191, 0.3);
    transition: var(--transition);
    text-align: center;
}

.service-card:hover {
    transform: translateY(-8px);
    border-color: var(--secondary);
    background: linear-gradient(135deg, var(--surface) 0%, rgba(214, 179, 255, 0.2) 100%);
    box-shadow: 0 20px 40px rgba(139, 95, 191, 0.25);
}

.service-icon {
    font-size: 3rem;
    margin-bottom: var(--spacing-md);
}

.service-card h3 {
    font-size: 1.3rem;
    margin-bottom: var(--spacing-md);
    color: var(--secondary);
}

.service-card p {
    color: var(--text-secondary);
    line-height: 1.7;
}

/* =============== CONTACT FORM =============== */
.contact {
    padding: var(--spacing-xl) var(--spacing-lg);
    background: linear-gradient(135deg, rgba(42, 30, 62, 0.8) 0%, rgba(31, 26, 63, 0.8) 100%);
    border-top: 2px solid rgba(139, 95, 191, 0.3);
}

.contact-container {
    max-width: 600px;
    margin: 0 auto;
}

.form-group {
    margin-bottom: var(--spacing-lg);
}

.form-group label {
    display: block;
    margin-bottom: var(--spacing-xs);
    color: var(--text-primary);
    font-weight: 600;
    font-size: 0.95rem;
}

.form-group input,
.form-group textarea {
    width: 100%;
    padding: var(--spacing-sm);
    background: rgba(255, 255, 255, 0.05);
    border: 2px solid rgba(139, 95, 191, 0.3);
    border-radius: 10px;
    color: var(--text-primary);
    font-family: inherit;
    font-size: 1rem;
    transition: var(--transition);
}

.form-group input::placeholder,
.form-group textarea::placeholder {
    color: rgba(255, 255, 255, 0.4);
}

.form-group input:focus,
.form-group textarea:focus {
    outline: none;
    border-color: var(--secondary);
    background: rgba(255, 255, 255, 0.08);
    box-shadow: 0 0 0 3px rgba(214, 179, 255, 0.1);
}

.form-group textarea {
    resize: vertical;
    min-height: 120px;
}

.form-submit {
    width: 100%;
    padding: 1rem;
    background: linear-gradient(135deg, var(--secondary) 0%, var(--accent-light) 100%);
    color: #000;
    border: none;
    border-radius: 10px;
    font-weight: 600;
    font-size: 1rem;
    cursor: pointer;
    transition: var(--transition);
    text-transform: uppercase;
    letter-spacing: 1px;
    box-shadow: 0 10px 30px rgba(214, 179, 255, 0.3);
}

.form-submit:hover {
    transform: translateY(-3px);
    box-shadow: 0 15px 40px rgba(214, 179, 255, 0.5);
}

.form-submit:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.form-message {
    margin-top: var(--spacing-md);
    padding: var(--spacing-md);
    border-radius: 10px;
    text-align: center;
    display: none;
    animation: slideInUp 0.3s ease-out;
}

.form-message.success {
    display: block;
    background: rgba(46, 204, 113, 0.2);
    color: var(--success);
    border: 1px solid var(--success);
}

.form-message.error {
    display: block;
    background: rgba(214, 179, 255, 0.2);
    color: var(--secondary);
    border: 1px solid var(--secondary);
}

/* =============== SOCIAL LINKS =============== */
.social-links {
    display: flex;
    justify-content: center;
    gap: var(--spacing-lg);
    margin-top: var(--spacing-lg);
    flex-wrap: wrap;
}

.social-link {
    width: 50px;
    height: 50px;
    border-radius: 10px;
    background: linear-gradient(135deg, var(--surface) 0%, rgba(214, 179, 255, 0.2) 100%);
    border: 2px solid rgba(139, 95, 191, 0.3);
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--secondary);
    text-decoration: none;
    transition: var(--transition);
    font-size: 1.2rem;
    font-weight: bold;
}

.social-link:hover {
    border-color: var(--secondary);
    background: linear-gradient(135deg, var(--secondary) 0%, var(--accent-light) 100%);
    color: #000;
    transform: translateY(-5px);
}

/* =============== FLOATING BUTTONS =============== */
.floating-buttons {
    position: fixed;
    bottom: var(--spacing-lg);
    right: var(--spacing-lg);
    z-index: 100;
    display: flex;
    flex-direction: column;
    gap: var(--spacing-md);
}

.floating-btn {
    width: 60px;
    height: 60px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    text-decoration: none;
    font-size: 1.5rem;
    transition: var(--transition);
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
    animation: bounceIn 0.6s cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

@keyframes bounceIn {
    from {
        opacity: 0;
        transform: scale(0);
    }

    to {
        opacity: 1;
        transform: scale(1);
    }
}

.whatsapp-btn {
    background: linear-gradient(135deg, #25d366 0%, #20ba5a 100%);
    color: white;
}

.whatsapp-btn:hover {
    transform: scale(1.1) rotate(10deg);
    box-shadow: 0 15px 40px rgba(37, 211, 102, 0.5);
}

/* =============== FOOTER =============== */
.footer {
    padding: var(--spacing-lg);
    text-align: center;
    color: var(--text-secondary);
    border-top: 1px solid rgba(139, 95, 191, 0.2);
}

/* =============== RESPONSIVE =============== */
@media (max-width: 768px) {
    .about-content {
        grid-template-columns: 1fr;
    }

    .nav-links {
        gap: var(--spacing-md);
        flex-direction: column;
    }

    .floating-buttons {
        bottom: var(--spacing-md);
        right: var(--spacing-md);
        gap: var(--spacing-sm);
    }

    .floating-btn {
        width: 50px;
        height: 50px;
        font-size: 1.2rem;
    }

    .cta-buttons {
        gap: var(--spacing-sm);
    }

    .btn {
        padding: 0.8rem 1.5rem;
        font-size: 0.9rem;
    }

    .timeline::before {
        left: 0;
    }

    .timeline-item:nth-child(odd),
    .timeline-item:nth-child(even) {
        padding-left: var(--spacing-lg);
        padding-right: 0;
        text-align: left;
    }

    .timeline-dot {
        left: 0;
    }
}

@media (max-width: 600px) {
    .hero {
        padding: var(--spacing-md);
        padding-top: 100px;
    }

    .about {
        margin: var(--spacing-md);
    }

    .navbar {
        padding: var(--spacing-sm) var(--spacing-md);
    }

    .nav-links {
        display: none;
    }

    .hero-content {
        animation: none;
    }

    h1 {
        font-size: 2rem;
    }

    .subtitle {
        font-size: 1rem;
    }

    .portfolio-grid {
        grid-template-columns: 1fr;
    }
}
